  it.todo("should kill center cell of fully surrounded 3x3 — overpopulation (Rule 3): input ### / .#. / ### includes (1,1) which dies");
  it.todo("should bring dead cell (1,1) to life when it has exactly 3 live neighbors (Rule 4): ##. / #.. / ... → ##. / ##. / ...");
  it.todo("should oscillate vertical blinker [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
  it.todo("should handle negative coordinates: blinker at [(-1,-1),(-1,0),(-1,1)] → [(-2,0),(-1,0),(0,0)]");
});

