        const nx = x + dx;
        const ny = y + dy;
        const k = key(nx, ny);
        const entry = neighborCounts.get(k);
        if (entry) entry.count++;
        else neighborCounts.set(k, { cell: [nx, ny], count: 1 });
      }
    }
  }

